const runtime = __importStar(require("@prisma/client/runtime/client"));
const config = {
    "previewFeatures": [],
    "clientVersion": "7.3.0",
    "engineVersion": "9d6ad21cbbceab97458517b147a6a09ff43aa735",
    "activeProvider": "postgresql",
    "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider     = \"prisma-client\"\n  output       = \"../generated/prisma\"\n  moduleFormat = \"cjs\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// =============================================================================\n// RÔLES & UTILISATEURS\n// =============================================================================\n\nenum Role {\n  PARTICULIER\n  PRESTATAIRE\n  ADMIN\n}\n\nmodel User {\n  id            String   @id @default(cuid())\n  email         String   @unique\n  passwordHash  String   @map(\"password_hash\")\n  role          Role\n  emailVerified Boolean  @default(false) @map(\"email_verified\")\n  fcmToken      String?  @map(\"fcm_token\") @db.Text\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n  updatedAt     DateTime @updatedAt @map(\"updated_at\")\n\n  particulier   Particulier?\n  prestataire   Prestataire?\n  notifications Notification[]\n\n  @@map(\"users\")\n}\n\n// =============================================================================\n// PROFILS\n// =============================================================================\n\n/// Compte client : INACTIF = fermeture / demande de suppression, sans supprimer la ligne.\nenum ParticulierStatut {\n  ACTIF\n  INACTIF\n}\n\nmodel Particulier {\n  id        String            @id @default(cuid())\n  userId    String            @unique @map(\"user_id\")\n  nom       String\n  prenom    String\n  telephone String?\n  adresse   String?\n  latitude  Decimal?          @db.Decimal(10, 7)\n  longitude Decimal?          @db.Decimal(10, 7)\n  avatarUrl String?           @map(\"avatar_url\")\n  statut    ParticulierStatut @default(ACTIF) @map(\"statut\")\n  createdAt DateTime          @default(now()) @map(\"created_at\")\n  updatedAt DateTime          @updatedAt @map(\"updated_at\")\n\n  user        User              @relation(fields: [userId], references: [id], onDelete: Cascade)\n  prestations Prestation[]\n  avis        AvisPrestataire[]\n\n  @@map(\"particuliers\")\n}\n\nmodel Prestataire {\n  id                 String                        @id @default(cuid())\n  userId             String                        @unique @map(\"user_id\")\n  nom                String // nom du prestataire ou de l'entreprise\n  telephone          String?\n  adresse            String?                       @db.Text\n  bio                String?                       @db.Text\n  avatarUrl          String?                       @map(\"avatar_url\")\n  zoneIntervention   String[]                      @map(\"zone_intervention\") // ex: [\"75001\", \"75002\", \"92\"] ou villes\n  latitude           Decimal?                      @db.Decimal(10, 7)\n  longitude          Decimal?                      @db.Decimal(10, 7)\n  actif              Boolean                       @default(true)\n  statutVerification StatutVerificationPrestataire @default(NON_VERIFIE) @map(\"statut_verification\")\n  createdAt          DateTime                      @default(now()) @map(\"created_at\")\n  updatedAt          DateTime                      @updatedAt @map(\"updated_at\")\n\n  user               User                  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  servicesProposes   PrestataireService[]\n  prestations        Prestation[]\n  documents          PrestataireDocument[]\n  avis               AvisPrestataire[]\n  abonnements        Abonnement[]\n  photos             PrestatairePhoto[]\n  wallet             Wallet?\n  withdrawalRequests WithdrawalRequest[]\n\n  @@map(\"prestataires\")\n}\n\n// =============================================================================\n// OFFRES & ABONNEMENTS (prestataires)\n// =============================================================================\n\nmodel Offre {\n  id          String   @id @default(cuid())\n  code        String   @unique // ex: \"mensuel\", \"trimestriel\", \"annuel\"\n  libelle     String\n  description String?  @db.Text\n  prix        Decimal  @db.Decimal(10, 2) // en FCFA ou unité choisie\n  dureeMois   Int      @map(\"duree_mois\") // 1, 3, 12, etc.\n  actif       Boolean  @default(true)\n  ordre       Int      @default(0)\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  abonnements        Abonnement[]\n  walletTransactions WalletTransaction[]\n\n  @@map(\"offres\")\n}\n\nenum StatutAbonnement {\n  ACTIF\n  EXPIRE\n  ANNULE\n}\n\nmodel Abonnement {\n  id            String           @id @default(cuid())\n  prestataireId String           @map(\"prestataire_id\")\n  offreId       String           @map(\"offre_id\")\n  dateDebut     DateTime         @map(\"date_debut\") @db.Date\n  dateFin       DateTime         @map(\"date_fin\") @db.Date\n  statut        StatutAbonnement @default(ACTIF)\n  createdAt     DateTime         @default(now()) @map(\"created_at\")\n  updatedAt     DateTime         @updatedAt @map(\"updated_at\")\n\n  prestataire        Prestataire         @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n  offre              Offre               @relation(fields: [offreId], references: [id], onDelete: Restrict)\n  walletTransactions WalletTransaction[]\n\n  @@index([prestataireId])\n  @@index([statut])\n  @@index([dateFin])\n  @@map(\"abonnements\")\n}\n\n// Statut global de vérification d'un prestataire en fonction de ses documents\nenum StatutVerificationPrestataire {\n  NON_VERIFIE // vient de s'inscrire, pas encore déposé les docs\n  EN_ATTENTE // docs déposés, en attente de validation admin\n  VERIFIE // tous les documents obligatoires sont validés\n  REFUSE // dossier refusé (documents non conformes)\n}\n\n// =============================================================================\n// DOCUMENTS OBLIGATOIRES PRESTATAIRES (validation admin)\n// =============================================================================\n\n// Types de documents requis (KBis, assurance RC pro, diplôme, etc.)\nmodel TypeDocument {\n  id          String   @id @default(cuid())\n  code        String   @unique // ex: \"kbis\", \"assurance_rc_pro\", \"carte_identite\"\n  libelle     String\n  description String?  @db.Text\n  obligatoire Boolean  @default(true)\n  ordre       Int      @default(0) // ordre d'affichage\n  actif       Boolean  @default(true)\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  documents PrestataireDocument[]\n\n  @@map(\"type_documents\")\n}\n\nenum StatutDocument {\n  EN_ATTENTE // déposé, en attente de validation admin\n  VALIDE\n  REFUSE\n}\n\n// Document déposé par un prestataire (fichier + statut de validation par l'admin)\nmodel PrestataireDocument {\n  id             String         @id @default(cuid())\n  prestataireId  String         @map(\"prestataire_id\")\n  typeDocumentId String         @map(\"type_document_id\")\n  fichierUrl     String         @map(\"fichier_url\") // URL ou clé de stockage (S3, etc.)\n  nomFichier     String?        @map(\"nom_fichier\") // nom original pour affichage\n  statut         StatutDocument @default(EN_ATTENTE)\n  validePar      String?        @map(\"valide_par\") // userId de l'admin\n  valideAt       DateTime?      @map(\"valide_at\")\n  motifRefus     String?        @map(\"motif_refus\") @db.Text\n  createdAt      DateTime       @default(now()) @map(\"created_at\")\n  updatedAt      DateTime       @updatedAt @map(\"updated_at\")\n\n  prestataire  Prestataire  @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n  typeDocument TypeDocument @relation(fields: [typeDocumentId], references: [id], onDelete: Restrict)\n\n  @@unique([prestataireId, typeDocumentId]) // un document par type et par prestataire (dernier dépôt = version courante)\n  @@index([prestataireId])\n  @@index([statut])\n  @@map(\"prestataire_documents\")\n}\n\n// =============================================================================\n// CATALOGUE PHOTOS PRESTATAIRES\n// =============================================================================\n//\n// Photos de réalisations / prestations rattachées au profil du prestataire.\nmodel PrestatairePhoto {\n  id            String   @id @default(cuid())\n  prestataireId String   @map(\"prestataire_id\")\n  url           String // URL de la photo (Cloudinary, etc.)\n  titre         String?\n  description   String?  @db.Text\n  ordre         Int      @default(0)\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  prestataire Prestataire @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n\n  @@index([prestataireId, ordre])\n  @@map(\"prestataire_photos\")\n}\n\n// =============================================================================\n// CATÉGORIES & SERVICES\n// =============================================================================\n\nmodel Service {\n  id          String   @id @default(cuid())\n  libelle     String\n  slug        String   @unique\n  description String?  @db.Text\n  icone       String? // nom ou URL de l'icône\n  tarifs      String?  @db.Text // configuration générique de fourchettes de prix (ex: JSON)\n  actif       Boolean  @default(true)\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  prestataires PrestataireService[]\n\n  @@map(\"services\")\n}\n\n// Services proposés par un prestataire (tarif, durée, etc.)\nmodel PrestataireService {\n  id             String   @id @default(cuid())\n  prestataireId  String   @map(\"prestataire_id\")\n  serviceId      String   @map(\"service_id\")\n  tarifHoraire   Decimal? @map(\"tarif_horaire\") @db.Decimal(10, 2) // en €\n  dureeDefautMin Int?     @map(\"duree_defaut_min\") // durée par défaut en minutes\n  description    String?  @db.Text\n  actif          Boolean  @default(true)\n  createdAt      DateTime @default(now()) @map(\"created_at\")\n  updatedAt      DateTime @updatedAt @map(\"updated_at\")\n\n  prestataire Prestataire  @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n  service     Service      @relation(fields: [serviceId], references: [id], onDelete: Cascade)\n  prestations Prestation[]\n\n  @@unique([prestataireId, serviceId])\n  @@map(\"prestataire_services\")\n}\n\n// =============================================================================\n// PRESTATIONS (demande → acceptation → en cours → terminée → paiement)\n// =============================================================================\n\nenum StatutPrestation {\n  EN_ATTENTE // créée par le particulier, en attente d'acceptation par le prestataire\n  ACCEPTEE // acceptée par le prestataire (avant passage en cours)\n  REFUSEE // refusée par le prestataire\n  EN_COURS // prestation en cours\n  TERMINEE // terminée par le prestataire, en attente de paiement\n  ANNULEE\n  PAYEE // payée par le particulier (prestataire notifié)\n}\n\n// =============================================================================\n// WALLETS & TRANSACTIONS (ledger)\n// =============================================================================\n\nenum WalletType {\n  GENERAL\n  PRESTATAIRE\n}\n\n/// Accès aux retraits pour le wallet prestataire (crédits prestations toujours possibles sauf plafond).\nenum PrestataireWalletStatut {\n  ACTIF\n  BLOQUE\n}\n\nenum TransactionType {\n  PRESTATION\n  ABONNEMENT\n}\n\nenum WithdrawalMethod {\n  ORANGE_MONEY\n  WAVE\n  FREE_MONEY\n  RIB\n}\n\nenum WithdrawalStatus {\n  EN_ATTENTE\n  TRAITE\n  REFUSE\n}\n\nmodel Wallet {\n  id                String                  @id @default(cuid())\n  type              WalletType\n  prestataireId     String?                 @unique @map(\"prestataire_id\")\n  balance           Decimal                 @default(0) @db.Decimal(14, 2)\n  /// Solde maximal du wallet (FCFA) : après tout crédit, le solde ne peut pas dépasser cette valeur. Null = sans limite.\n  balancePlafond    Decimal?                @map(\"balance_plafond\") @db.Decimal(14, 2)\n  /// Gel : bloque les demandes de retrait côté prestataire.\n  statutPrestataire PrestataireWalletStatut @default(ACTIF) @map(\"statut_prestataire_wallet\")\n  createdAt         DateTime                @default(now()) @map(\"created_at\")\n  updatedAt         DateTime                @updatedAt @map(\"updated_at\")\n\n  prestataire  Prestataire?        @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n  transactions WalletTransaction[]\n\n  @@map(\"wallets\")\n}\n\nmodel WalletTransaction {\n  id              String          @id @default(cuid())\n  walletId        String          @map(\"wallet_id\")\n  type            TransactionType\n  amount          Decimal         @db.Decimal(14, 2)\n  prestationId    String?         @map(\"prestation_id\")\n  abonnementId    String?         @map(\"abonnement_id\")\n  offreId         String?         @map(\"offre_id\")\n  meta            Json?\n  createdByUserId String?         @map(\"created_by_user_id\")\n  createdAt       DateTime        @default(now()) @map(\"created_at\")\n\n  wallet     Wallet      @relation(fields: [walletId], references: [id], onDelete: Cascade)\n  prestation Prestation? @relation(fields: [prestationId], references: [id], onDelete: SetNull)\n  abonnement Abonnement? @relation(fields: [abonnementId], references: [id], onDelete: SetNull)\n  offre      Offre?      @relation(fields: [offreId], references: [id], onDelete: SetNull)\n\n  @@unique([walletId, type, prestationId])\n  @@unique([walletId, type, abonnementId])\n  @@index([walletId, createdAt])\n  @@index([type, createdAt])\n  @@map(\"wallet_transactions\")\n}\n\n// =============================================================================\n// DEMANDES DE RETRAIT (wallet -> traitement manuel)\n// =============================================================================\n\nmodel WithdrawalRequest {\n  id            String           @id @default(cuid())\n  prestataireId String           @map(\"prestataire_id\")\n  method        WithdrawalMethod\n  status        WithdrawalStatus @default(EN_ATTENTE)\n  meta          Json?\n  createdAt     DateTime         @default(now()) @map(\"created_at\")\n  updatedAt     DateTime         @updatedAt @map(\"updated_at\")\n\n  prestataire Prestataire @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n\n  @@index([prestataireId])\n  @@map(\"withdrawal_requests\")\n}\n\nmodel Prestation {\n  id                   String           @id @default(cuid())\n  particulierId        String           @map(\"particulier_id\")\n  prestataireId        String           @map(\"prestataire_id\")\n  prestataireServiceId String           @map(\"prestataire_service_id\")\n  typeDeTache          String?          @map(\"type_de_tache\")\n  description          String?          @db.Text\n  imageUrl             String?          @map(\"image_url\")\n  budget               Decimal?         @db.Decimal(10, 2)\n  adresse              String?          @db.Text\n  codePostal           String?          @map(\"code_postal\")\n  ville                String?\n  noteParticulier      String?          @map(\"note_particulier\") @db.Text\n  statut               StatutPrestation @default(EN_ATTENTE)\n  acceptedAt           DateTime?        @map(\"accepted_at\")\n  completedAt          DateTime?        @map(\"completed_at\")\n  createdAt            DateTime         @default(now()) @map(\"created_at\")\n  updatedAt            DateTime         @updatedAt @map(\"updated_at\")\n\n  particulier        Particulier         @relation(fields: [particulierId], references: [id], onDelete: Cascade)\n  prestataire        Prestataire         @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n  prestataireService PrestataireService  @relation(fields: [prestataireServiceId], references: [id], onDelete: Restrict)\n  walletTransactions WalletTransaction[]\n\n  @@index([particulierId])\n  @@index([prestataireId])\n  @@index([statut])\n  @@map(\"prestations\")\n}\n\n// =============================================================================\n// NOTIFICATIONS (push + in-app)\n// =============================================================================\n\nmodel Notification {\n  id        String   @id @default(cuid())\n  userId    String   @map(\"user_id\")\n  title     String   @db.Text\n  body      String?  @db.Text\n  type      String? // ex: \"prestation_created\", \"prestation_accepted\"\n  data      Json? // payload pour la navigation (prestationId, etc.)\n  lu        Boolean  @default(false)\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([userId, lu])\n  @@map(\"notifications\")\n}\n\n// =============================================================================\n// AVIS / NOTATION PRESTATAIRES (note sur 5 étoiles)\n// =============================================================================\n\nmodel AvisPrestataire {\n  id            String   @id @default(cuid())\n  particulierId String   @map(\"particulier_id\")\n  prestataireId String   @map(\"prestataire_id\")\n  note          Int // 1 à 5 étoiles\n  commentaire   String?  @db.Text\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  particulier Particulier @relation(fields: [particulierId], references: [id], onDelete: Cascade)\n  prestataire Prestataire @relation(fields: [prestataireId], references: [id], onDelete: Cascade)\n\n  @@unique([particulierId, prestataireId]) // un avis par particulier par prestataire\n  @@index([prestataireId])\n  @@map(\"avis_prestataire\")\n}\n",
    "runtimeDataModel": {
        "models": {},
        "enums": {},
        "types": {}
    }
};
